const incoming = $('Receive WhatsApp Message').item.json;

// 1. Drop the event immediately if it's NOT a standard user text message
if (!incoming.messages || !incoming.messages[0] || incoming.messages[0].type !== 'text') {
    return []; // Empty array stops the workflow silently
}

const msgId = incoming.messages[0].id;
const userPhone = incoming.contacts[0].wa_id;

// $getWorkflowStaticData only works when the workflow is ACTIVE (Published).
// It saves data across executions.
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedIds) staticData.processedIds = {};

// 2. Check if already processed (Meta Retry Prevention)
const key = `${userPhone}:${msgId}`;
if (staticData.processedIds[key]) {
  // Duplicate detected — stop execution silently to break the loop
  return []; 
}

// 3. Mark as processed
staticData.processedIds[key] = Date.now();

// 4. Memory management (keep last 200 IDs to avoid unbounded growth)
const keys = Object.keys(staticData.processedIds);
if (keys.length > 200) {
  keys.sort((a, b) => staticData.processedIds[a] - staticData.processedIds[b]);
  delete staticData.processedIds[keys[0]];
}

return $input.all();

const raw = $json.output || '';

// All fields always present — prevents downstream undefined issues
const defaults = {
  reply: '',
  Location: '',
  Size_sqft: '',       
  Size_sqft_op: '',
  Size_sqft_min: '',   
  Size_sqft_max: '',
  Type: '',
  Price_Lakh: '',      
  Price_Lakh_op: '',
  Price_Lakh_min: '',  
  Price_Lakh_max: '',
  Bedrooms: '',        
  Bedrooms_op: '',
  Furnished: ''
};

try {
  // Strip markdown fences, extract JSON object
  const cleaned = raw
    .replace(/```json[\s\S]*?```/g, m => m.slice(7, -3))
    .replace(/```/g, '')
    .trim();

  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON object found in output');

  const parsed = JSON.parse(jsonMatch[0]);

  // Normalize operator strings to lowercase
  const opFields = [
    'Price_Lakh_op','Size_sqft_op','Bedrooms_op'
  ];
  for (const f of opFields) {
    if (parsed[f]) {
      parsed[f] = String(parsed[f]).toLowerCase().trim();
    }
  }

  // Normalize location to lowercase
  if (parsed.Location) {
    const loc = String(parsed.Location).toLowerCase().trim();
    parsed.Location = ['any', 'any area', 'anywhere',
                       'all areas', 'any location'].includes(loc)
      ? 'any' : loc; // <--- THIS IS THE FIX. Changed '' to 'any'
  }

  // Normalize type to lowercase
  if (parsed.Type) {
    parsed.Type = String(parsed.Type).toLowerCase().trim();
  }

  // Merge parsed over defaults so all fields always exist
  return [{ json: { ...defaults, ...parsed } }];

} catch (err) {
  return [{ json: { ...defaults, _parseError: err.message } }];
}

const newData = $('Parse & Clean LLM Output').first().json;
const oldRow = $input.first()?.json || {};

const pick = (n, o) =>
  (n !== undefined && n !== null && String(n).trim() !== '') ? n : (o || '');

return [{
  json: {
    User_Number:    $('Receive WhatsApp Message').item.json.contacts[0].wa_id,
    Location:       pick(newData.Location,       oldRow.location),
    Type:           pick(newData.Type,           oldRow.type),
    Price_Lakh:     pick(newData.Price_Lakh,     oldRow['price-lakhs']),
    Price_Lakh_op:  pick(newData.Price_Lakh_op,  oldRow['price-lakh-op']),
    Price_Lakh_min: pick(newData.Price_Lakh_min, oldRow['price-lakh-min']),
    Price_Lakh_max: pick(newData.Price_Lakh_max, oldRow['price-lakh-max']),
    Size_sqft:      pick(newData.Size_sqft,      oldRow['size-sqft']),
    Size_sqft_op:   pick(newData.Size_sqft_op,   oldRow['size-sqft-op']),
    Size_sqft_min:  pick(newData.Size_sqft_min,  oldRow['size-sqft-min']),
    Size_sqft_max:  pick(newData.Size_sqft_max,  oldRow['size-sqft-max']),
    Bedrooms:       pick(newData.Bedrooms,       oldRow.bedrooms),
    Bedrooms_op:    pick(newData.Bedrooms_op,    oldRow['bedrooms-op'])
  }
}];

const j = $('Combine New Text with History').first().json;

// Helper to check if a field has data (including the word "any")
function isFieldPresent(val) {
  if (val === undefined || val === null) return false;
  const str = String(val).toLowerCase().trim();
  return str !== ''; 
}

const hasLocation = isFieldPresent(j.Location);
const hasType = isFieldPresent(j.Type);
const hasPrice = isFieldPresent(j.Price_Lakh); 

// Location and Type are mandatory. Price is optional.
const readyToSearch = hasLocation && hasType && hasPrice;

return [{
  json: {
    ...j,
    readyToSearch,
    hasLocation,
    hasType,
    hasPrice
  }
}];

const req = $('Combine New Text with History').first().json;

function normalize(v){
  return String(v || '').toLowerCase().trim();
}

const location = normalize(req.Location);
const type = normalize(req.Type);

const ahmedabadAreas = [
  'south bopal','bopal','satellite','gota','prahlad nagar','sg highway',
  'thaltej','bodakdev','navrangpura','chandkheda','science city',
  'vastral','nikol','shela','ambli','vasna','maninagar','new ranip','ranip'
];

const isAhmedabadSearch = (location === 'ahmedabad');
const inventory = $input.all();

const matches = inventory.filter(item => {
  const row = item.json;
  const rowLocation = normalize(row.Location);
  const rowType = normalize(row.Type);
  const available = normalize(row.Available);

  if (available !== 'yes' && available !== 'maybe') return false;

  // --- LOCATION FILTER (Skip if "any") ---
  if (location !== 'any' && location !== '') {
    if (isAhmedabadSearch) {
      const matchedAhmedabadArea = ahmedabadAreas.some(area => rowLocation.includes(area));
      if (!matchedAhmedabadArea) return false;
    } else if (!rowLocation.includes(location)) {
      return false;
    }
  }

  // --- TYPE FILTER (Skip if "any") ---
  if (type !== 'any' && type !== '') {
    if (!rowType.includes(type)) return false;
  }

  // ── PRICE / BUDGET FILTER ──────────────────────────────────────────
  const priceRaw = req.Price_Lakh;
  const priceOp  = String(req.Price_Lakh_op || '').toLowerCase().trim();
  const hasPrice = (
    priceRaw !== '' &&
    priceRaw !== null &&
    priceRaw !== undefined &&
    priceRaw !== 'any'
  );

  if (hasPrice) {
    const budget = Number(priceRaw);
    const rowPrice = Number(row.Price_Lakh || 0); // Added to ensure rowPrice is defined

    if (!isNaN(budget)) {
      if (priceOp === 'min') {
        // above / more than / greater than / over / minimum / 60 lakh+
        if (rowPrice <= budget) return false;
      } else if (priceOp === 'max') {
        // under / below / less than / lower than
        if (rowPrice >= budget) return false;
      } else if (priceOp === 'max_inclusive') {
        // up to / at most / no more than / maximum
        if (rowPrice > budget) return false;
      } else if (priceOp === 'min_inclusive') {
        // at least / no less than
        if (rowPrice < budget) return false;
      } else if (priceOp === 'exact') {
        // exactly X lakh
        if (rowPrice !== budget) return false;
      } else if (priceOp === 'approx') {
        // around / approximately / about
        const tolerance = budget * 0.15;
        if (Math.abs(rowPrice - budget) > tolerance) return false;
      } else if (priceOp === 'between') {
        // between X and Y lakh
        const bMin = Number(req.Price_Lakh_min || 0);
        const bMax = Number(req.Price_Lakh_max || Infinity);
        if (rowPrice < bMin || rowPrice > bMax) return false;
      } else {
        // Default fallback: treat plain number as ceiling (max)
        if (rowPrice > budget) return false;
      }
    }
  }
  // If !hasPrice → any budget → no price filter → all prices pass through

  // ── SIZE FILTER ─────────────────────────────────────────────────────
  const sizeRaw = req.Size_sqft;
  const sizeOp  = String(req.Size_sqft_op || '').toLowerCase().trim();
  const hasSize = (
    sizeRaw !== '' &&
    sizeRaw !== null &&
    sizeRaw !== undefined &&
    sizeRaw !== 'any'
  );

  if (hasSize) {
    const requestedSize = Number(sizeRaw);
    const rowSize = Number(row.Size_sqft || 0);

    if (!isNaN(requestedSize)) {
      if (sizeOp === 'min') {
        if (rowSize <= requestedSize) return false;
      } else if (sizeOp === 'max') {
        if (rowSize >= requestedSize) return false;
      } else if (sizeOp === 'max_inclusive') {
        if (rowSize > requestedSize) return false;
      } else if (sizeOp === 'min_inclusive') {
        if (rowSize < requestedSize) return false;
      } else if (sizeOp === 'approx') {
        const tol = requestedSize * 0.15;
        if (Math.abs(rowSize - requestedSize) > tol) return false;
      } else if (sizeOp === 'between') {
        const sMin = Number(req.Size_sqft_min || 0);
        const sMax = Number(req.Size_sqft_max || Infinity);
        if (rowSize < sMin || rowSize > sMax) return false;
      } else {
        // exact fallback
        if (rowSize !== requestedSize) return false;
      }
    }
  }

  return true;
});

if (matches.length === 0) {
  return [{ json: { noMatch: true } }];
}

return [{ json: { properties: matches, count: matches.length } }];

const properties = $json.properties || [];

if (properties.length === 0) {

return [{
json: {
reply:
`No matching properties found.

You can type "Hi" to start a new search.`
}
}];

}

const limited = properties.slice(0, 10);

let reply =
`🏡 Here are some matching properties:

`;

for (const prop of limited) {

const row = prop.json || {};

reply +=
`• ${row.Property_ID || ''}
📍 ${row.Location || ''}
🏠 ${row.Type || ''}
📐 ${row.Size_sqft || ''} sqft
💰 ${row.Price_Lakh || ''} Lakh

`;

}

reply +=
`👨‍💼 Interested in any property?

Type: Agent

Or contact:
📞 123456789`;

return [{
json: {
...$json,
reply
}
}];

