(() => {
  // Pulling the flags directly from the Code node so they aren't erased
  const check = $('Check if Ready to Search').first().json;
  let missing = [];

  if (!check.hasLocation) {
    missing.push('📍 Location');
  }
  if (!check.hasType) {
    missing.push('🏠 Property Type');
  }
  if (!check.hasPrice) {
    missing.push('💰 Budget (You can also say "any budget" or "no limit")');
  }

  return `Please share:\n\n${missing.join('\n')}\n\nExample:\nFlat in Ahmedabad under 80 lakh`;
})()
}}
